@namespace CheckoutWizard
@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <legend>Shipping Information</legend>

    <div class="form-group">
        <label for="name">Full Name</label>
        <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address</label>
        <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="city">City</label>
        <input id="city" @bind="Shipping.City" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="zip">Zip Code</label>
        <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_validationError))
{
    <div class="validation-error" role="alert">@_validationError</div>
}

<div class="button-bar">
    <button class="btn-next" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner" aria-hidden="true"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _validationError;
    private CancellationTokenSource? _cts;

    private async Task HandleNext()
    {
        if (_isValidating) return;

        _validationError = null;

        if (string.IsNullOrWhiteSpace(Shipping.Name) ||
            string.IsNullOrWhiteSpace(Shipping.Address) ||
            string.IsNullOrWhiteSpace(Shipping.City) ||
            string.IsNullOrWhiteSpace(Shipping.ZipCode))
        {
            _validationError = "All shipping fields are required.";
            return;
        }

        // Cancel any previous in-flight validation.
        CancelPendingValidation();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled (user navigated away or re-clicked) — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

